const now = new Date();
const today = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const timeStr = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Chicago' });
const dayOfWeek = now.toLocaleDateString('en-US', { weekday: 'long', timeZone: 'America/Chicago' });
return [{ json: { today, timeStr, dayOfWeek, updatedAt: `${dayOfWeek}, ${today} at ${timeStr} CT` } }];

const { today, timeStr, dayOfWeek, updatedAt } = $('Set Time').first().json;

let mtl = '';
let mtlReadFailed = false;
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  mtl = buf.toString('utf-8');
} catch(e) {
  mtlReadFailed = true;
}

if (mtlReadFailed || !mtl.trim()) {
  return [{ json: { _skip: true, reason: 'MTL read failed — preserving existing dashboard', today, updatedAt } }];
}

// ── Parse tasks ────────────────────────────────────────────────────────────
const AREAS = ['faith','family','business','consulting','work','health','home','personal'];
const AREA_EMOJI = { faith:'🙏', family:'👨‍👩‍👧', business:'🚀', consulting:'💼', work:'🏥', health:'💪', home:'🏠', personal:'🎯' };

const allOpen = [], allDone = [];
const openRe = /^- \[ \] (.+?)\[area:: (\w+)\].*?\[priority:: ([ABC])\](?:.*?\[due:: (\d{4}-\d{2}-\d{2})\])?/gm;
const doneRe = /^- \[x\] (.+?)\[area:: (\w+)\]/gm;
let m;
while ((m = openRe.exec(mtl)) !== null) allOpen.push({ task: m[1].trim(), area: m[2], priority: m[3], due: m[4]||null });
while ((m = doneRe.exec(mtl)) !== null) allDone.push({ area: m[2] });

const overdue   = allOpen.filter(t => t.due && t.due < today)
  .map(t => ({ ...t, daysOverdue: Math.floor((new Date(today)-new Date(t.due))/86400000) }))
  .sort((a,b) => { if(a.priority!==b.priority) return a.priority<b.priority?-1:1; return b.daysOverdue-a.daysOverdue; });
const dueToday  = allOpen.filter(t => t.due === today)
  .sort((a,b) => a.priority<b.priority?-1:a.priority>b.priority?1:0);
const upcoming  = allOpen.filter(t => t.due && t.due > today)
  .sort((a,b) => a.due<b.due?-1:a.due>b.due?1:0).slice(0,10);
const priorityA = allOpen.filter(t => t.priority==='A');
const quickWins = allOpen.filter(t => t.priority==='C' && (!t.due||t.due>=today)).slice(0,5);

const byArea = {};
const doneByArea = {};
for (const area of AREAS) {
  byArea[area]    = allOpen.filter(t => t.area===area);
  doneByArea[area]= allDone.filter(t => t.area===area).length;
}

// ── #1 Priority determination ──────────────────────────────────────────────
let topTask = null;
const criticalOverdue = overdue.find(t => t.priority==='A');
const todayA = dueToday.find(t => t.priority==='A');
const anyOverdue = overdue[0];
const anyToday = dueToday[0];
topTask = criticalOverdue || todayA || anyOverdue || anyToday || priorityA[0] || null;

// ── Q2 Rock tracking ───────────────────────────────────────────────────────
// Compute progress: (done Priority A in area) / (done + open Priority A in area)
const Q2_ROCKS = [
  { area:'faith',    emoji:'🙏', label:'Launch social media Bible study (4 sessions)' },
  { area:'family',   emoji:'👨‍👩‍👧', label:'Marriage Alignment + bi-weekly check-in' },
  { area:'business', emoji:'🚀', label:'Ship MVP — website, offer, 3 outreach convos' },
  { area:'work',     emoji:'🏥', label:'Deliver Union project' },
  { area:'health',   emoji:'💪', label:'Hip decision + 3x/week gym × 8 weeks' },
];
const openPriorityAByArea = {};
for (const area of AREAS) openPriorityAByArea[area] = byArea[area].filter(t=>t.priority==='A').length;

// ── Brain dump status ──────────────────────────────────────────────────────
// We can't easily check brain dump files from here, so we show a reminder message
// based on system time (runs hourly — brain dump processor runs at 7AM)
const hour = parseInt(timeStr.split(':')[0]);
const isAM = timeStr.includes('AM');
const brainDumpNote = (isAM && hour < 8) ? '⏳ Brain dump processor not yet run today' : 
                      (isAM && hour >= 7) ? '✅ Brain dump processor ran this morning' :
                      '✅ Brain dump processor ran this morning';

// ── Domain health scoring ──────────────────────────────────────────────────
function domainHealth(area) {
  const tasks = byArea[area];
  const overdueCount = tasks.filter(t => t.due && t.due < today).length;
  if (overdueCount >= 3) return '🔴';
  if (overdueCount >= 1) return '🟡';
  if (tasks.length === 0) return '⚪';
  return '🟢';
}

// ── Markdown builder ───────────────────────────────────────────────────────
let md = `---
type: live-dashboard
updated: ${today}T${timeStr}
---

# 🧠 Aaron's Life OS — ${dayOfWeek}, ${today}

> [!tip] 🎯 #1 PRIORITY RIGHT NOW
> ${topTask 
    ? `**${topTask.task}** \`${topTask.area}\` \`${topTask.priority}\`` + (topTask.daysOverdue ? ` — ⚠️ ${topTask.daysOverdue}d overdue` : topTask.due===today ? ' — 📅 due today' : '')
    : 'No urgent tasks — use this time to move a Q2 Rock forward.'}

`;

// ── Overdue ────────────────────────────────────────────────────────────────
if (overdue.length > 0) {
  const critical = overdue.filter(t=>t.daysOverdue>=8);
  const high     = overdue.filter(t=>t.daysOverdue>=4&&t.daysOverdue<8);
  const medium   = overdue.filter(t=>t.daysOverdue<4);
  md += `> [!danger] 🔥 Overdue — ${overdue.length} task${overdue.length>1?'s':''}\n`;
  if (critical.length) md += `> **CRITICAL (8+ days):** ${critical.length}\n`;
  if (high.length)     md += `> **High (4–7 days):** ${high.length}\n`;
  if (medium.length)   md += `> **Medium (1–3 days):** ${medium.length}\n>\n`;
  for (const t of overdue.slice(0,12)) {
    const badge = t.daysOverdue>=8?'🔴':t.daysOverdue>=4?'🟠':'🟡';
    md += `> ${badge} ${t.daysOverdue}d · **[${t.priority}]** ${t.task} \`${AREA_EMOJI[t.area]||'📌'} ${t.area}\`\n`;
  }
  if (overdue.length>12) md += `> *…and ${overdue.length-12} more overdue tasks*\n`;
  md += '\n';
} else {
  md += `> [!success] ✅ No overdue tasks — you're ahead of the game!\n\n`;
}

// ── Due today ─────────────────────────────────────────────────────────────
if (dueToday.length > 0) {
  md += `> [!warning] 📅 Due Today — ${dueToday.length} task${dueToday.length>1?'s':''}\n>\n`;
  for (const t of dueToday) {
    md += `> **[${t.priority}]** ${t.task} \`${AREA_EMOJI[t.area]||'📌'} ${t.area}\`\n`;
  }
  md += '\n';
} else {
  md += `> [!info] 📅 Nothing due today — good time to get ahead.\n\n`;
}

// ── Priority A (no due date) ───────────────────────────────────────────────
const floatingA = priorityA.filter(t => !t.due);
if (floatingA.length > 0) {
  md += `> [!warning]- 🪨 Priority A Rocks (no due date) — ${floatingA.length}\n>\n`;
  for (const t of floatingA.slice(0,8)) {
    md += `> **[A]** ${t.task} \`${AREA_EMOJI[t.area]||'📌'} ${t.area}\`\n`;
  }
  if (floatingA.length>8) md += `> *…and ${floatingA.length-8} more*\n`;
  md += '\n';
}

// ── Upcoming (next 7 days) ─────────────────────────────────────────────────
if (upcoming.length > 0) {
  md += `> [!info]- 📆 Upcoming — Next 7 Days (${upcoming.length})\n>\n`;
  for (const t of upcoming.slice(0,8)) {
    const daysUntil = Math.ceil((new Date(t.due)-new Date(today))/86400000);
    const urgency = daysUntil<=2?'⚡':daysUntil<=4?'📌':'📆';
    md += `> ${urgency} **${t.due}** (+${daysUntil}d) · [${t.priority}] ${t.task} \`${t.area}\`\n`;
  }
  md += '\n';
}

// ── Q2 2026 Rocks ─────────────────────────────────────────────────────────
md += `> [!note]- 🎯 Q2 2026 Quarterly Rocks\n>\n`;
for (const rock of Q2_ROCKS) {
  const open = openPriorityAByArea[rock.area] || 0;
  const done = doneByArea[rock.area] || 0;
  const status = open===0 ? '✅' : open<=2 ? '🟡' : '🔴';
  md += `> ${status} **${rock.emoji} ${rock.area}:** ${rock.label}\n`;
  md += `>    ${open} Priority A tasks open`;
  if (done>0) md += `, ${done} completed`;
  md += '\n';
}
md += '\n';

// ── Domain Pulse ──────────────────────────────────────────────────────────
md += `> [!abstract]- 🗂️ Domain Pulse — ${allOpen.length} open across 8 areas\n>\n`;
md += `> | Domain | Health | Open | 🔥 Overdue | 🔴 Priority A |\n`;
md += `> |--------|--------|------|-----------|---------------|\n`;
for (const area of AREAS) {
  const tasks = byArea[area];
  const ov = tasks.filter(t=>t.due&&t.due<today).length;
  const pa = tasks.filter(t=>t.priority==='A').length;
  const health = domainHealth(area);
  md += `> | ${AREA_EMOJI[area]} ${area} | ${health} | ${tasks.length} | ${ov||'—'} | ${pa||'—'} |\n`;
}
md += '\n';

// ── Quick Wins ────────────────────────────────────────────────────────────
if (quickWins.length > 0) {
  md += `> [!success]- ⚡ Quick Wins — Priority C (easy momentum)\n>\n`;
  for (const t of quickWins) {
    md += `> - [ ] ${t.task} \`${AREA_EMOJI[t.area]||'📌'} ${t.area}\`\n`;
  }
  md += '\n';
}

// ── System Status ─────────────────────────────────────────────────────────
md += `> [!example]- 🏥 System Status\n> ${brainDumpNote}\n> 🔄 Dashboard refreshed: ${updatedAt}\n> 📋 Total tasks tracked: **${allOpen.length} open**, ${allDone.length} completed in MTL\n\n`;

md += `---\n*Auto-refreshed hourly · ${allOpen.length} open tasks · Life OS powered by ObsidianHomeOrchestrator*\n`;

const buf = Buffer.from(md, 'utf-8');
return [{ json: {
  key: '000_Master Dashboard/Live Dashboard.md',
  today, updatedAt, totalTasks: allOpen.length,
  overdueCount: overdue.length, dueTodayCount: dueToday.length
}, binary: { data: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: 'Live Dashboard.md', fileExtension: 'md', fileSize: buf.length } } }];
